+                }
+            }
+        }
+
+        // Gravity
+        if !self.on_ground {
+            self.mom_z -= GRAVITY;
+        }
+
+        // Apply vertical movement
+        self.view_z += self.mom_z;
+        let target_z = self.floor_z + PLAYER_VIEW_HEIGHT;
+        if self.view_z <= target_z {
+            self.view_z = target_z;
+            self.mom_z = 0.0;
+            self.on_ground = true;
+        } else {
+            self.on_ground = false;
+        }
