+        assert!((p.x - 100.0).abs() < 0.01);
+        assert!((p.y - 200.0).abs() < 0.01);
+        assert!((p.angle - 1.5).abs() < 0.01);
+    }
+
+    #[test]
+    fn player_look_clamps_pitch() {
+        let mut p = Player::default();
+        p.look(0.0, 10.0);
+        assert!(p.pitch <= 1.2);
+        p.look(0.0, -20.0);
+        assert!(p.pitch >= -1.2);
+    }
