+#[cfg(feature = "canvas")]
+fn draw_canvas_line_pattern(
+    painter: &mut Painter,
+    x0: i32,
+    y0: i32,
+    x1: i32,
+    y1: i32,
+    on_len: usize,
+    off_len: usize,
+) {
+    let dx = (x1 - x0).abs();
+    let dy = -(y1 - y0).abs();
+    let sx: i32 = if x0 < x1 { 1 } else { -1 };
+    let sy: i32 = if y0 < y1 { 1 } else { -1 };
+    let mut err = dx + dy;
+    let mut cx = x0;
+    let mut cy = y0;
+
+    let mut draw_on = true;
+    let mut remaining = on_len.max(1);
+
+    loop {
+        if draw_on {
+            painter.point(cx, cy);
+        }
+
+        if cx == x1 && cy == y1 {
+            break;
+        }
+
+        let e2 = 2 * err;
+        if e2 >= dy {
+            if cx == x1 {
+                break;
+            }
+            err += dy;
+            cx += sx;
+        }
+        if e2 <= dx {
+            if cy == y1 {
+                break;
+            }
+            err += dx;
+            cy += sy;
+        }
+
+        remaining = remaining.saturating_sub(1);
+        if remaining == 0 {
+            draw_on = !draw_on;
+            remaining = if draw_on { on_len } else { off_len };
+            if remaining == 0 {
+                remaining = 1;
+            }
+        }
+    }
+}
