+fn render_canvas_nodes(
+    painter: &mut Painter,
+    nodes: &[LayoutNodeBox],
+    ir: &MermaidDiagramIr,
+    vp: &CanvasViewport,
+) {
+    for node in nodes {
+        let ir_node = match ir.nodes.get(node.node_idx) {
+            Some(node) => node,
+            None => continue,
+        };
+        if ir_node
+            .classes
